INSERT INTO `book_page` (`id`, `book_id`, `page_no`, `title`, `content_type`, `content_text_ko`, `content_text_en`, `image_url`, `created_at`, `updated_at`) VALUES
(1, 1, 1, '따뜻한 저녁', 'POEM', '비가 그치자 무지개가 마을을 감쌌습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다.', 'She found an old key hidden inside the wooden box. Two old friends sat by the river and shared their stories. Nobody in town could explain where the music came from. Every evening, the baker left a loaf of bread by the door. The garden was full of flowers no one remembered planting. Nobody expected the small boat to survive the storm.', NULL, '2026-05-12 19:48:13', '2026-05-15 19:48:13'),
(2, 1, 2, '비 오는 날', 'POEM', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 아이는 손을 흔들며 친구에게 인사했습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다.', 'The child looked out the window and smiled at the falling snow. The mountain path was steep, but the view was worth it.', 'https://cdn.sangsangseoga.com/page/2.png', '2026-04-11 09:35:42', '2026-04-16 09:35:42'),
(3, 1, 3, '새로운 친구', 'POEM', '바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다.', 'The garden was full of flowers no one remembered planting. The old clock in the hallway had stopped ticking years ago. Deep in the forest, something rustled quietly among the leaves.', 'https://cdn.sangsangseoga.com/page/3.png', '2025-07-21 10:59:21', '2025-08-04 10:59:21'),
(4, 1, 4, '작은 결심', 'POEM', '겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다.', 'She found an old key hidden inside the wooden box. The last page of the book was missing, and no one knew why. The mountain path was steep, but the view was worth it.', NULL, '2026-03-05 13:54:04', '2026-03-21 13:54:04'),
(5, 1, 5, '함께한 하루', 'POEM', '아이는 손을 흔들며 친구에게 인사했습니다.', 'The children built a small boat out of paper and leaves. She found an old key hidden inside the wooden box. Deep in the forest, something rustled quietly among the leaves. The last page of the book was missing, and no one knew why. The train pulled away just as she reached the platform.', 'https://cdn.sangsangseoga.com/page/5.png', '2025-10-19 19:32:04', '2025-11-07 19:32:04'),
(6, 1, 6, '함께한 하루', 'POEM', '비가 그치자 무지개가 마을을 감쌌습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'He took a deep breath and stepped through the old gate. Nobody in town could explain where the music came from. A warm cup of tea waited for him on the table. Nobody expected the small boat to survive the storm.', 'https://cdn.sangsangseoga.com/page/6.png', '2025-12-20 06:48:33', '2026-01-07 06:48:33'),
(7, 1, 7, '첫 만남', 'POEM', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'Every winter, the lake froze just enough to walk across. The children built a small boat out of paper and leaves. He took a deep breath and stepped through the old gate. She found an old key hidden inside the wooden box.', 'https://cdn.sangsangseoga.com/page/7.png', '2025-11-18 18:43:59', '2025-12-15 18:43:59'),
(8, 1, 8, '비 오는 날', 'POEM', '작은 실수도 함께 웃으며 넘길 수 있었습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 작은 마을에 사는 아이는 매일 창밖을 바라보았습니다.', 'The garden was full of flowers no one remembered planting. Two old friends sat by the river and shared their stories. Rain tapped gently on the roof while they slept. Deep in the forest, something rustled quietly among the leaves. The old clock in the hallway had stopped ticking years ago.', 'https://cdn.sangsangseoga.com/page/8.png', '2025-07-02 09:24:16', '2025-07-28 09:24:16'),
(9, 2, 1, '마지막 인사', 'CHAPTER', '함께라면 무엇이든 해낼 수 있을 것 같았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'Nobody expected the small boat to survive the storm.', 'https://cdn.sangsangseoga.com/page/9.png', '2025-10-07 10:01:55', '2025-11-05 10:01:55'),
(10, 2, 2, '새로운 친구', 'CHAPTER', '비가 그치자 무지개가 마을을 감쌌습니다.', 'A single candle lit the whole room with a warm glow.', 'https://cdn.sangsangseoga.com/page/10.png', '2025-04-25 05:08:59', '2025-05-16 05:08:59'),
(11, 2, 3, '첫 만남', 'CHAPTER', '함께라면 무엇이든 해낼 수 있을 것 같았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다.', 'The last page of the book was missing, and no one knew why. The dog barked twice, then ran ahead down the path. Every evening, the baker left a loaf of bread by the door. The child looked out the window and smiled at the falling snow. Nobody expected the small boat to survive the storm. The little village woke up slowly under the morning light.', 'https://cdn.sangsangseoga.com/page/11.png', '2025-05-20 22:21:32', '2025-05-27 22:21:32'),
(12, 2, 4, '약속의 순간', 'CHAPTER', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'Deep in the forest, something rustled quietly among the leaves. The dog barked twice, then ran ahead down the path. The child looked out the window and smiled at the falling snow. A soft breeze carried the smell of fresh bread through the street.', 'https://cdn.sangsangseoga.com/page/12.png', '2025-07-10 13:27:20', '2025-07-21 13:27:20'),
(13, 2, 5, '약속의 순간', 'CHAPTER', '모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다.', 'She held the letter close and read it one more time. Nobody in town could explain where the music came from. The child looked out the window and smiled at the falling snow. She found an old key hidden inside the wooden box. The little village woke up slowly under the morning light. The train pulled away just as she reached the platform.', 'https://cdn.sangsangseoga.com/page/13.png', '2026-03-22 03:43:27', '2026-04-03 03:43:27'),
(14, 2, 6, '첫 만남', 'CHAPTER', '오랜 기다림 끝에 반가운 소식이 도착했습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 아이는 손을 흔들며 친구에게 인사했습니다. 작은 실수도 함께 웃으며 넘길 수 있었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다.', 'The children built a small boat out of paper and leaves. She found an old key hidden inside the wooden box. A soft breeze carried the smell of fresh bread through the street. A warm cup of tea waited for him on the table. Nobody expected the small boat to survive the storm.', 'https://cdn.sangsangseoga.com/page/14.png', '2025-06-05 11:17:28', '2025-06-23 11:17:28'),
(15, 2, 7, '함께한 하루', 'CHAPTER', '달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'The children built a small boat out of paper and leaves. She held the letter close and read it one more time. A soft breeze carried the smell of fresh bread through the street. The lantern flickered as the wind grew stronger outside.', 'https://cdn.sangsangseoga.com/page/15.png', '2025-07-12 15:57:30', '2025-07-27 15:57:30'),
(16, 2, 8, '함께한 하루', 'CHAPTER', '처음엔 무서웠지만 곧 용기를 내기로 했습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다.', 'The garden was full of flowers no one remembered planting.', 'https://cdn.sangsangseoga.com/page/16.png', '2025-07-02 22:35:21', '2025-07-19 22:35:21'),
(17, 2, 9, '작은 결심', 'CHAPTER', '비가 그치자 무지개가 마을을 감쌌습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'The fox watched them from behind a fallen tree. Every evening, the baker left a loaf of bread by the door. She held the letter close and read it one more time.', 'https://cdn.sangsangseoga.com/page/17.png', '2025-09-30 17:31:44', '2025-10-04 17:31:44'),
(18, 2, 10, '마지막 인사', 'CHAPTER', '작은 실수도 함께 웃으며 넘길 수 있었습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 아이는 손을 흔들며 친구에게 인사했습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다.', 'The fox watched them from behind a fallen tree. He took a deep breath and stepped through the old gate. The garden was full of flowers no one remembered planting. Nobody in town could explain where the music came from. The lantern flickered as the wind grew stronger outside.', 'https://cdn.sangsangseoga.com/page/18.png', '2026-02-03 16:31:33', '2026-02-22 16:31:33'),
(19, 2, 11, '다시 만난 날', 'CHAPTER', '작은 마을에 사는 아이는 매일 창밖을 바라보았습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'The little village woke up slowly under the morning light. The train pulled away just as she reached the platform. The last page of the book was missing, and no one knew why. Rain tapped gently on the roof while they slept.', 'https://cdn.sangsangseoga.com/page/19.png', '2025-11-24 06:14:01', '2025-12-24 06:14:01'),
(20, 2, 12, '마지막 인사', 'CHAPTER', '겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'Two old friends sat by the river and shared their stories. The old clock in the hallway had stopped ticking years ago. The stars seemed closer than ever that quiet night.', NULL, '2025-06-04 10:27:00', '2025-06-10 10:27:00'),
(21, 2, 13, '비 오는 날', 'CHAPTER', '모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 작은 실수도 함께 웃으며 넘길 수 있었습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다.', 'Two old friends sat by the river and shared their stories. The fox watched them from behind a fallen tree. She held the letter close and read it one more time. Nobody in town could explain where the music came from. Every evening, the baker left a loaf of bread by the door.', 'https://cdn.sangsangseoga.com/page/21.png', '2026-04-30 13:54:26', '2026-05-16 13:54:26'),
(22, 2, 14, '돌아오는 길', 'CHAPTER', '오랜 기다림 끝에 반가운 소식이 도착했습니다. 작은 마을에 사는 아이는 매일 창밖을 바라보았습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'Every winter, the lake froze just enough to walk across. A single candle lit the whole room with a warm glow.', 'https://cdn.sangsangseoga.com/page/22.png', '2026-01-02 04:04:32', '2026-01-23 04:04:32'),
(23, 2, 15, '작은 기적', 'CHAPTER', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다.', 'The train pulled away just as she reached the platform. Nobody expected the small boat to survive the storm. The stars seemed closer than ever that quiet night. Two old friends sat by the river and shared their stories. The child looked out the window and smiled at the falling snow. The fox watched them from behind a fallen tree.', 'https://cdn.sangsangseoga.com/page/23.png', '2026-01-29 03:15:17', '2026-02-13 03:15:17'),
(24, 2, 16, '따뜻한 저녁', 'CHAPTER', '겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 작은 실수도 함께 웃으며 넘길 수 있었습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다.', 'Every evening, the baker left a loaf of bread by the door. The train pulled away just as she reached the platform.', NULL, '2026-05-03 13:02:15', '2026-05-03 13:02:15'),
(25, 2, 17, '작은 결심', 'CHAPTER', '새로운 친구를 만난 순간, 마음이 두근거렸습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다.', 'Nobody expected the small boat to survive the storm.', 'https://cdn.sangsangseoga.com/page/25.png', '2025-08-08 16:13:35', '2025-08-17 16:13:35'),
(26, 2, 18, '돌아오는 길', 'CHAPTER', '바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다.', 'Nobody in town could explain where the music came from. The stars seemed closer than ever that quiet night. The mountain path was steep, but the view was worth it. A soft breeze carried the smell of fresh bread through the street. Two old friends sat by the river and shared their stories. Every winter, the lake froze just enough to walk across.', 'https://cdn.sangsangseoga.com/page/26.png', '2025-08-12 00:38:37', '2025-08-29 00:38:37'),
(27, 2, 19, '마지막 인사', 'CHAPTER', '숲속에서 들려오는 소리에 귀를 기울였습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다.', 'He took a deep breath and stepped through the old gate. Two old friends sat by the river and shared their stories. A warm cup of tea waited for him on the table.', NULL, '2026-02-08 14:20:49', '2026-02-26 14:20:49'),
(28, 3, 1, '마지막 인사', 'CHAPTER', '모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다.', 'She held the letter close and read it one more time. The last page of the book was missing, and no one knew why. The little village woke up slowly under the morning light. The mountain path was steep, but the view was worth it. He took a deep breath and stepped through the old gate. Rain tapped gently on the roof while they slept.', 'https://cdn.sangsangseoga.com/page/28.png', '2026-03-10 02:34:06', '2026-03-27 02:34:06'),
(29, 3, 2, '돌아오는 길', 'CHAPTER', '숲속에서 들려오는 소리에 귀를 기울였습니다.', 'A single candle lit the whole room with a warm glow. Every winter, the lake froze just enough to walk across. A soft breeze carried the smell of fresh bread through the street. Rain tapped gently on the roof while they slept. She held the letter close and read it one more time.', 'https://cdn.sangsangseoga.com/page/29.png', '2026-05-09 05:25:20', '2026-05-12 05:25:20'),
(30, 3, 3, '따뜻한 저녁', 'CHAPTER', '새로운 친구를 만난 순간, 마음이 두근거렸습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다.', 'Every winter, the lake froze just enough to walk across. She found an old key hidden inside the wooden box. The fox watched them from behind a fallen tree. Deep in the forest, something rustled quietly among the leaves. The old clock in the hallway had stopped ticking years ago. The train pulled away just as she reached the platform.', NULL, '2026-04-16 05:29:29', '2026-05-12 05:29:29'),
(31, 3, 4, '작은 결심', 'CHAPTER', '달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다.', 'The dog barked twice, then ran ahead down the path. She found an old key hidden inside the wooden box. The last page of the book was missing, and no one knew why. A single candle lit the whole room with a warm glow.', NULL, '2026-04-15 09:40:46', '2026-05-11 09:40:46'),
(32, 3, 5, '돌아오는 길', 'CHAPTER', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다.', 'The garden was full of flowers no one remembered planting.', 'https://cdn.sangsangseoga.com/page/32.png', '2026-01-27 04:55:40', '2026-02-13 04:55:40'),
(33, 4, 1, '마지막 인사', 'CHAPTER', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 작은 마을에 사는 아이는 매일 창밖을 바라보았습니다.', 'The garden was full of flowers no one remembered planting. Rain tapped gently on the roof while they slept. The stars seemed closer than ever that quiet night.', NULL, '2026-01-14 14:42:59', '2026-01-17 14:42:59'),
