INSERT INTO `book_review` (`id`, `member_id`, `book_id`, `content`, `is_draft`, `ai_feedback_content`, `ai_feedback_created_at`, `created_at`, `updated_at`) VALUES
(1, 11, 119, '아이가 스스로 몇 번이나 읽었을 만큼 좋아했습니다. 짧은 분량이지만 여운이 오래 남습니다.', 0, '전개가 자연스럽고 이해하기 쉽습니다.', '2026-03-06 23:35:43', '2026-02-13 23:35:43', '2026-03-06 23:35:43'),
(2, 6, 81, '다음 편이 있다면 꼭 다시 보고 싶습니다. 주인공의 성장 과정이 인상 깊었습니다.', 0, NULL, NULL, '2026-05-02 20:54:47', '2026-05-11 20:54:47'),
(3, 36, 146, '결말 부분에서 감동을 받았습니다.', 0, NULL, NULL, '2026-06-29 21:08:04', '2026-07-03 09:15:31'),
(4, 19, 106, '짧은 분량이지만 여운이 오래 남습니다. 잔잔하지만 마음에 남는 이야기였습니다. 아이가 스스로 몇 번이나 읽었을 만큼 좋아했습니다.', 0, '짧지만 완성도 높은 이야기입니다.', '2026-06-01 17:13:17', '2026-05-19 17:13:17', '2026-06-01 17:13:17'),
(5, 49, 68, '짧은 분량이지만 여운이 오래 남습니다. 아이와 함께 읽으며 많은 이야기를 나눌 수 있었습니다. 그림책 특유의 따뜻함이 잘 살아있는 작품입니다.', 0, '결말의 여운이 좋습니다.', '2026-01-20 20:23:09', '2025-12-28 20:23:09', '2026-01-20 20:23:09'),
(6, 51, 19, '잔잔하지만 마음에 남는 이야기였습니다. 결말 부분에서 감동을 받았습니다. 다음 편이 있다면 꼭 다시 보고 싶습니다.', 0, '감정 표현이 풍부합니다.', '2026-01-21 23:21:01', '2026-01-02 23:21:01', '2026-01-21 23:21:01'),
(7, 39, 63, '아이와 함께 읽으며 많은 이야기를 나눌 수 있었습니다. 주인공의 성장 과정이 인상 깊었습니다. 잔잔하지만 마음에 남는 이야기였습니다.', 0, '따뜻한 문체가 돋보입니다.', '2026-07-03 09:15:31', '2026-06-25 19:33:17', '2026-07-03 09:15:31'),
(8, 55, 67, '잔잔하지만 마음에 남는 이야기였습니다. 아이와 함께 읽으며 많은 이야기를 나눌 수 있었습니다. 아이가 스스로 몇 번이나 읽었을 만큼 좋아했습니다.', 0, '전개가 자연스럽고 이해하기 쉽습니다.', '2026-01-09 11:47:18', '2025-12-22 11:47:18', '2026-01-09 11:47:18'),
(9, 57, 70, '결말 부분에서 감동을 받았습니다. 다음 편이 있다면 꼭 다시 보고 싶습니다. 잔잔하지만 마음에 남는 이야기였습니다.', 0, '감정 표현이 풍부합니다.', '2026-02-20 13:58:11', '2026-02-12 13:58:11', '2026-02-20 13:58:11'),
(10, 54, 144, '주인공의 성장 과정이 인상 깊었습니다. 다음 편이 있다면 꼭 다시 보고 싶습니다. 아이가 스스로 몇 번이나 읽었을 만큼 좋아했습니다.', 0, '전개가 자연스럽고 이해하기 쉽습니다.', '2025-11-15 22:14:18', '2025-11-11 22:14:18', '2025-11-15 22:14:18'),
